# 1) Stop all OpenVPN clients
Get-Process OpenVPNConnect, openvpn-gui, openvpn -ErrorAction SilentlyContinue | Stop-Process -Force -ErrorAction SilentlyContinue
Start-Sleep -Seconds 2

# 2) Disable conflicting adapters (Community TAP + DCO), keep Connect TAP
$keepName = 'TAP-Windows Adapter V9 for OpenVPN Connect'
Get-NetAdapter | Where-Object {
  $_.InterfaceDescription -match 'TAP-Windows|Data Channel Offload|Wintun' -or $_.Name -match 'OpenVPN'
} | ForEach-Object {
  $desc = $_.InterfaceDescription
  $action = if ($desc -eq $keepName) { 'KEEP' } else { 'DISABLE' }
  Write-Host "$action ifIndex=$($_.ifIndex) name=$($_.Name) desc=$desc status=$($_.Status)"
  if ($action -eq 'DISABLE') {
    Disable-NetAdapter -Name $_.Name -Confirm:$false -ErrorAction SilentlyContinue
  } else {
    Enable-NetAdapter -Name $_.Name -Confirm:$false -ErrorAction SilentlyContinue
  }
}

# 3) Raise Radmin metric so it stops winning
try {
  Set-NetIPInterface -InterfaceAlias 'Radmin VPN' -InterfaceMetric 5000 -ErrorAction Stop
  Write-Host 'Radmin metric -> 5000'
} catch { Write-Host "Radmin metric skip: $($_.Exception.Message)" }

# 4) Clean leftover 10.8 routes
$bad = Get-NetRoute -AddressFamily IPv4 -ErrorAction SilentlyContinue | Where-Object {
  $_.DestinationPrefix -match '^(0\.0\.0\.0/1|128\.0\.0\.0/1)$' -or
  ($_.DestinationPrefix -eq '5.188.18.103/32' -and $_.NextHop -eq '192.168.2.1' -and $_.RouteMetric -ne 0) -or
  $_.NextHop -eq '10.8.0.1'
}
$bad | ForEach-Object {
  Write-Host "remove route $($_.DestinationPrefix) via $($_.NextHop) if $($_.InterfaceIndex)"
  Remove-NetRoute -DestinationPrefix $_.DestinationPrefix -InterfaceIndex $_.InterfaceIndex -NextHop $_.NextHop -Confirm:$false -ErrorAction SilentlyContinue
}

# Clear IPs on Connect TAP except link-local will refresh
$tap = Get-NetAdapter | Where-Object { $_.InterfaceDescription -eq $keepName }
if ($tap) {
  Get-NetIPAddress -InterfaceIndex $tap.ifIndex -AddressFamily IPv4 -ErrorAction SilentlyContinue |
    Where-Object { $_.IPAddress -like '10.8.*' } |
    ForEach-Object { Remove-NetIPAddress -IPAddress $_.IPAddress -PrefixLength $_.PrefixLength -Confirm:$false -ErrorAction SilentlyContinue }
  Write-Host "Connect TAP ifIndex=$($tap.ifIndex) status=$($tap.Status)"
}

Write-Host '=== adapters now ==='
Get-NetAdapter | Where-Object { $_.InterfaceDescription -match 'TAP|Offload|Radmin|Realtek' } |
